void __thiscall RAMFileClass::~RAMFileClass(RAMFileClass *this)

{
  LPVOID lpMem;
  HANDLE hHeap;

  lpMem = (this->RAMFileClass_data).offset_0x0;
  this->vftablePtr = &vftable;
  if (lpMem != (LPVOID)0x0) {
    hHeap = GetProcessHeap();
    HeapFree(hHeap,0,lpMem);
  }
  (this->RAMFileClass_data).offset_0x0 = (LPVOID)0x0;
  FileClass::~FileClass((FileClass *)this);
  return;
}
